selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2 </span><i class=\"fa-regular fa-map\"></i> Operation Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"robot_connection.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.2.1 </span>Download Links<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2><h3>iOS<a class=\"headerlink\" href=\"#ios\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"shutdown.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.4.1 </span>Assist the Robot to Lie Down (No Gantry Required)<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Step 1: Enter Standing Preparation Mode (Position-Control Standing)<a class=\"headerlink\" href=\"#step-1\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"shutdown.html#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.4.2 </span>Shutdown from Sitting Posture (No Gantry Required)<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Step 1: Use the Controller to Make the Robot Sit<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"remote_controller.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.3.1 </span>Operation Steps<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>1. Open the \u201cAdd Robot\u201d page</strong></p>", "a[href=\"start_up_guide.html#sdk\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1.1 </span>Startup While Suspended (Gantry Required) (Recommended for SDK use)<a class=\"headerlink\" href=\"#sdk\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Step 1: Unbox and Position Properly</strong> Open the package as shown and carefully lift the robot out. Use the support frame to suspend the robot naturally, ensuring that the feet do not touch the ground.</p>", "a[href=\"start_up_guide.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1 </span>Startup Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.1.1 </span>Startup While Suspended (Gantry Required) (Recommended for SDK use)<a class=\"headerlink\" href=\"#sdk\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Step 1: Unbox and Position Properly</strong> Open the package as shown and carefully lift the robot out. Use the support frame to suspend the robot naturally, ensuring that the feet do not touch the ground.</p>", "a[href=\"shutdown.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.4 </span>Shutdown Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.4.1 </span>Assist the Robot to Lie Down (No Gantry Required)<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Step 1: Enter Standing Preparation Mode (Position-Control Standing)<a class=\"headerlink\" href=\"#step-1\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"remote_controller.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.3 </span>Remote Controller Connection<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.3.1 </span>Operation Steps<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>1. Open the \u201cAdd Robot\u201d page</strong></p>", "a[href=\"robot_connection.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.2 </span>Robot Mobile App Connection (Agibot Go APP)<a class=\"headerlink\" href=\"#app-agibot-go-app\" title=\"Link to this heading\">\uf0c1</a></h1><p>The latest app version must match the robot\u2019s latest firmware version. Please download the correct version.</p>", "a[href=\"start_up_guide.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1.2 </span>Startup from Supine Position (No Gantry Required)<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Step 1: Unbox and Position Properly</strong> Open the package as shown and gently lift the robot to avoid collisions. Position the robot as shown to check battery level or install the battery.</p>", "a[href=\"start_up_guide.html#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1.3 </span>Startup from Sitting Position (No Gantry Required)<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Step 1: Unbox and Position Properly</strong> Open the robot\u2019s package as shown and lift it out carefully. Position the robot as shown to check the battery or install it.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
